mapper.select:
SELECT f.id AS id, u.id AS user_id, u.display_name AS display_name, u.avatar_url AS avatar_url,

FROM follows f JOIN users u ON u.id = f.follower_id
WHERE f.followee_id = #{targetUserId}
AND f.id < #{cursor}
ORDER BY f.id DESC
LIMIT #{limit}

